-- ==================== 20260615120700_functions.sql ====================
-- Atomic booking-core RPCs. PostgREST cannot run app-level transactions or
-- SELECT FOR UPDATE, so all locking/atomic logic lives here and is called via
-- supabase.rpc(...). Each function body is one transaction. SECURITY DEFINER so
-- controlled writes work under RLS; search_path pinned for safety.

-- Role check used by RLS policies. SECURITY DEFINER so its read of `profiles`
-- bypasses RLS (avoids policy recursion).
create or replace function is_staff()
returns boolean
language sql
stable
security definer
set search_path = public
as $$
  select exists (
    select 1 from profiles where id = auth.uid() and role in ('staff', 'admin')
  );
$$;

-- Seats currently taken for an occurrence: confirmed booking_items + active,
-- non-expired holds. Availability = occurrence.capacity - used_capacity().
create or replace function used_capacity(p_occurrence_id uuid)
returns int
language sql
stable
security definer
set search_path = public
as $$
  select
    coalesce((
      select sum(bi.quantity)
      from booking_items bi
      join bookings b on b.id = bi.booking_id
      where bi.session_occurrence_id = p_occurrence_id
        and b.status in ('confirmed', 'completed')
    ), 0)
    + coalesce((
      select sum(h.quantity)
      from booking_holds h
      where h.session_occurrence_id = p_occurrence_id
        and h.status = 'active'
        and h.expires_at > now()
    ), 0);
$$;

-- Atomic hold creation: lock the occurrence, compute availability, insert. Idempotent.
create or replace function create_hold(
  p_occurrence_id uuid,
  p_quantity int,
  p_idempotency_key text
)
returns booking_holds
language plpgsql
security definer
set search_path = public
as $$
declare
  v_existing booking_holds;
  v_occ session_occurrences;
  v_available int;
  v_hold booking_holds;
begin
  if p_quantity is null or p_quantity <= 0 then
    raise exception 'invalid_quantity' using detail = 'quantity must be > 0';
  end if;

  -- Idempotent replay: same key returns the same hold, no second reservation.
  select * into v_existing from booking_holds where idempotency_key = p_idempotency_key;
  if found then
    return v_existing;
  end if;

  -- Row lock serialises concurrent holds on the same occurrence.
  select * into v_occ from session_occurrences where id = p_occurrence_id for update;
  if not found then
    raise exception 'occurrence_not_found';
  end if;
  if v_occ.status <> 'open' then
    raise exception 'occurrence_not_bookable' using detail = v_occ.status::text;
  end if;

  v_available := v_occ.capacity - used_capacity(p_occurrence_id);
  if p_quantity > v_available then
    raise exception 'insufficient_capacity'
      using detail = format('requested %s, available %s', p_quantity, v_available);
  end if;

  insert into booking_holds (session_occurrence_id, quantity, idempotency_key)
  values (p_occurrence_id, p_quantity, p_idempotency_key)
  returning * into v_hold;
  return v_hold;
end;
$$;

create or replace function release_hold(p_hold_id uuid)
returns booking_holds
language plpgsql
security definer
set search_path = public
as $$
declare
  v_hold booking_holds;
begin
  update booking_holds set status = 'released'
  where id = p_hold_id and status = 'active'
  returning * into v_hold;
  if not found then
    raise exception 'hold_not_active';
  end if;
  return v_hold;
end;
$$;

-- Sweeper (pg_cron): flip stale active holds to expired. Capacity already ignores
-- them (expires_at > now()), so this is for clean state/reporting.
create or replace function expire_holds()
returns int
language plpgsql
security definer
set search_path = public
as $$
declare
  v_count int;
begin
  update booking_holds set status = 'expired'
  where status = 'active' and expires_at <= now();
  get diagnostics v_count = row_count;
  return v_count;
end;
$$;

-- Atomic booking creation from an active hold. Idempotent on p_idempotency_key.
-- The hold stays active (still reserving capacity) until payment confirms.
create or replace function create_booking(
  p_idempotency_key text,
  p_hold_id uuid,
  p_customer_name text,
  p_customer_email text,
  p_customer_phone text,
  p_source booking_source,
  p_items jsonb
)
returns bookings
language plpgsql
security definer
set search_path = public
as $$
declare
  v_existing bookings;
  v_hold booking_holds;
  v_booking bookings;
  v_item jsonb;
  v_qty int;
  v_unit int;
  v_total int := 0;
  v_qty_total int := 0;
begin
  select * into v_existing from bookings where idempotency_key = p_idempotency_key;
  if found then
    return v_existing;
  end if;

  select * into v_hold from booking_holds where id = p_hold_id for update;
  if not found then
    raise exception 'hold_not_found';
  end if;
  if v_hold.status <> 'active' or v_hold.expires_at <= now() then
    raise exception 'hold_not_active';
  end if;

  for v_item in select * from jsonb_array_elements(p_items) loop
    v_qty := (v_item ->> 'quantity')::int;
    v_unit := (v_item ->> 'unit_amount_minor')::int;
    if v_qty is null or v_qty <= 0 or v_unit is null or v_unit < 0 then
      raise exception 'invalid_item';
    end if;
    v_qty_total := v_qty_total + v_qty;
    v_total := v_total + (v_qty * v_unit);
  end loop;

  if v_qty_total <> v_hold.quantity then
    raise exception 'items_quantity_mismatch'
      using detail = format('items %s, hold %s', v_qty_total, v_hold.quantity);
  end if;

  insert into bookings (
    idempotency_key, customer_name, customer_email, customer_phone, source,
    status, total_minor, operator_payout_minor, agency_commission_minor
  )
  values (
    p_idempotency_key, p_customer_name, p_customer_email, p_customer_phone,
    coalesce(p_source, 'web'), 'payment_pending', v_total, v_total, 0
  )
  returning * into v_booking;

  for v_item in select * from jsonb_array_elements(p_items) loop
    insert into booking_items (
      booking_id, session_occurrence_id, activity_option_id, price_label,
      quantity, unit_amount_minor, subtotal_minor
    )
    values (
      v_booking.id,
      v_hold.session_occurrence_id,
      (v_item ->> 'activity_option_id')::uuid,
      v_item ->> 'price_label',
      (v_item ->> 'quantity')::int,
      (v_item ->> 'unit_amount_minor')::int,
      (v_item ->> 'quantity')::int * (v_item ->> 'unit_amount_minor')::int
    );
  end loop;

  update booking_holds set booking_id = v_booking.id where id = v_hold.id;
  return v_booking;
end;
$$;

-- Append a payment event (idempotent on provider_event_id), re-derive the cached
-- projection from the FULL ledger (order-independent), and project onto the booking.
-- Confirms the booking + consumes its holds on first 'paid'. Called by the verified
-- webhook (service_role) only — never a frontend success page.
create or replace function append_payment_event(
  p_payment_id uuid,
  p_type text,
  p_provider_event_id text,
  p_amount_minor int,
  p_occurred_at timestamptz,
  p_payload jsonb
)
returns payments
language plpgsql
security definer
set search_path = public
as $$
declare
  v_payment payments;
  v_paid int;
  v_refunded int;
  v_failed boolean;
  v_state payment_state;
begin
  insert into payment_events (payment_id, type, provider_event_id, amount_minor, occurred_at, payload)
  values (
    p_payment_id, p_type, p_provider_event_id, coalesce(p_amount_minor, 0),
    coalesce(p_occurred_at, now()), coalesce(p_payload, '{}'::jsonb)
  )
  on conflict (payment_id, provider_event_id) do nothing;

  select
    coalesce(sum(amount_minor) filter (where type in ('paid', 'captured')), 0),
    coalesce(sum(amount_minor) filter (where type = 'refunded'), 0),
    bool_or(type = 'failed')
  into v_paid, v_refunded, v_failed
  from payment_events
  where payment_id = p_payment_id;

  select * into v_payment from payments where id = p_payment_id for update;
  if not found then
    raise exception 'payment_not_found';
  end if;

  if v_paid > 0 and v_refunded >= v_paid then
    v_state := 'refunded';
  elsif v_refunded > 0 then
    v_state := 'partially_refunded';
  elsif v_paid > 0 then
    v_state := 'paid';
  elsif coalesce(v_failed, false) then
    v_state := 'failed';
  else
    v_state := 'pending';
  end if;

  update payments
  set status = v_state, paid_minor = v_paid, refunded_minor = v_refunded, updated_at = now()
  where id = p_payment_id
  returning * into v_payment;

  update bookings set payment_state = v_state, updated_at = now() where id = v_payment.booking_id;

  if v_state = 'paid' then
    update bookings set status = 'confirmed', updated_at = now()
    where id = v_payment.booking_id and status in ('draft', 'held', 'payment_pending');
    update booking_holds set status = 'consumed'
    where booking_id = v_payment.booking_id and status = 'active';
  elsif v_state = 'refunded' then
    update bookings set status = 'refunded', updated_at = now()
    where id = v_payment.booking_id and status <> 'cancelled';
  end if;

  return v_payment;
end;
$$;

-- ==================== 20260615120800_rls.sql ====================
-- Row Level Security on every table (deny-by-default) + grants + function execute
-- permissions. Supabase model: broad table grants to anon/authenticated, with RLS
-- doing the real row-level gating. service_role bypasses RLS (webhook/cron/admin).

-- ---------------------------------------------------------------------------
-- Grants (RLS still filters rows for anon/authenticated)
-- ---------------------------------------------------------------------------
grant usage on schema public to anon, authenticated, service_role;
grant select, insert, update, delete on all tables in schema public to authenticated;
grant select, insert on all tables in schema public to anon;
grant all on all tables in schema public to service_role;

-- Append-only tables: no UPDATE/DELETE for anyone via the API (inserts go through
-- SECURITY DEFINER RPCs / triggers that run as the table owner).
revoke update, delete on payment_events from anon, authenticated, service_role;
revoke update, delete on audit_logs from anon, authenticated, service_role;

-- Enable RLS everywhere.
alter table operators enable row level security;
alter table profiles enable row level security;
alter table activities enable row level security;
alter table activity_translations enable row level security;
alter table activity_images enable row level security;
alter table activity_options enable row level security;
alter table activity_option_prices enable row level security;
alter table session_occurrences enable row level security;
alter table booking_holds enable row level security;
alter table bookings enable row level security;
alter table booking_items enable row level security;
alter table payments enable row level security;
alter table payment_events enable row level security;
alter table notification_outbox enable row level security;
alter table audit_logs enable row level security;
alter table leads enable row level security;
alter table reviews enable row level security;
alter table chat_sessions enable row level security;
alter table chat_messages enable row level security;

-- ---------------------------------------------------------------------------
-- Operators — public read, staff manage
-- ---------------------------------------------------------------------------
create policy operators_read on operators for select using (true);
create policy operators_staff on operators for all using (is_staff()) with check (is_staff());

-- ---------------------------------------------------------------------------
-- Profiles — own row, staff see all
-- ---------------------------------------------------------------------------
create policy profiles_select on profiles for select using (id = auth.uid() or is_staff());
create policy profiles_insert on profiles for insert with check (id = auth.uid());
create policy profiles_update on profiles for update
  using (id = auth.uid() or is_staff()) with check (id = auth.uid() or is_staff());
create policy profiles_staff on profiles for all using (is_staff()) with check (is_staff());

-- ---------------------------------------------------------------------------
-- Catalogue — public reads PUBLISHED only; staff manage everything
-- ---------------------------------------------------------------------------
create policy activities_read on activities for select using (status = 'published' or is_staff());
create policy activities_staff on activities for all using (is_staff()) with check (is_staff());

create policy activity_translations_read on activity_translations for select using (
  exists (select 1 from activities a where a.id = activity_id and (a.status = 'published' or is_staff()))
);
create policy activity_translations_staff on activity_translations for all
  using (is_staff()) with check (is_staff());

create policy activity_images_read on activity_images for select using (
  exists (select 1 from activities a where a.id = activity_id and (a.status = 'published' or is_staff()))
);
create policy activity_images_staff on activity_images for all
  using (is_staff()) with check (is_staff());

create policy activity_options_read on activity_options for select using (
  exists (select 1 from activities a where a.id = activity_id and (a.status = 'published' or is_staff()))
);
create policy activity_options_staff on activity_options for all
  using (is_staff()) with check (is_staff());

create policy aop_read on activity_option_prices for select using (
  exists (
    select 1 from activity_options o
    join activities a on a.id = o.activity_id
    where o.id = activity_option_id and (a.status = 'published' or is_staff())
  )
);
create policy aop_staff on activity_option_prices for all using (is_staff()) with check (is_staff());

-- ---------------------------------------------------------------------------
-- Inventory — public sees occurrences of published activities; staff manage
-- ---------------------------------------------------------------------------
create policy occurrences_read on session_occurrences for select using (
  is_staff() or exists (
    select 1 from activity_options o
    join activities a on a.id = o.activity_id
    where o.id = activity_option_id and a.status = 'published'
  )
);
create policy occurrences_staff on session_occurrences for all using (is_staff()) with check (is_staff());

-- Holds are internal (managed by RPCs); only staff read directly.
create policy holds_staff on booking_holds for all using (is_staff()) with check (is_staff());

-- ---------------------------------------------------------------------------
-- Bookings — customers see/insert their own; staff manage
-- ---------------------------------------------------------------------------
create policy bookings_select on bookings for select using (user_id = auth.uid() or is_staff());
create policy bookings_insert on bookings for insert with check (user_id = auth.uid() or is_staff());
create policy bookings_staff on bookings for all using (is_staff()) with check (is_staff());

create policy booking_items_select on booking_items for select using (
  exists (select 1 from bookings b where b.id = booking_id and (b.user_id = auth.uid() or is_staff()))
);
create policy booking_items_staff on booking_items for all using (is_staff()) with check (is_staff());

-- ---------------------------------------------------------------------------
-- Payments — customer reads own (via booking); writes only via RPC/service_role
-- ---------------------------------------------------------------------------
create policy payments_select on payments for select using (
  is_staff() or exists (select 1 from bookings b where b.id = booking_id and b.user_id = auth.uid())
);
create policy payments_staff on payments for all using (is_staff()) with check (is_staff());

-- payment_events: read own/staff; append-only (no write policies -> denied; inserts via RPC).
create policy payment_events_select on payment_events for select using (
  is_staff() or exists (
    select 1 from payments p join bookings b on b.id = p.booking_id
    where p.id = payment_id and b.user_id = auth.uid()
  )
);

-- ---------------------------------------------------------------------------
-- Ops tables
-- ---------------------------------------------------------------------------
create policy outbox_staff on notification_outbox for all using (is_staff()) with check (is_staff());

-- audit_logs: staff read; append-only (inserts via RPC/trigger as owner).
create policy audit_select on audit_logs for select using (is_staff());

-- Leads: anyone may capture a lead; staff read/manage.
create policy leads_insert on leads for insert with check (true);
create policy leads_staff on leads for all using (is_staff()) with check (is_staff());

-- Reviews: public read; authenticated may submit; staff manage.
create policy reviews_read on reviews for select using (true);
create policy reviews_insert on reviews for insert with check (auth.uid() is not null);
create policy reviews_staff on reviews for all using (is_staff()) with check (is_staff());

-- Chat: owner or staff.
create policy chat_sessions_select on chat_sessions for select using (user_id = auth.uid() or is_staff());
create policy chat_sessions_insert on chat_sessions for insert with check (user_id = auth.uid() or user_id is null);
create policy chat_sessions_staff on chat_sessions for all using (is_staff()) with check (is_staff());

create policy chat_messages_select on chat_messages for select using (
  exists (select 1 from chat_sessions s where s.id = session_id and (s.user_id = auth.uid() or is_staff()))
);
create policy chat_messages_staff on chat_messages for all using (is_staff()) with check (is_staff());

-- ---------------------------------------------------------------------------
-- Function execute permissions
-- ---------------------------------------------------------------------------
revoke execute on function append_payment_event(uuid, text, text, int, timestamptz, jsonb) from public;
grant execute on function append_payment_event(uuid, text, text, int, timestamptz, jsonb) to service_role;

revoke execute on function expire_holds() from public;
grant execute on function expire_holds() to service_role;

grant execute on function create_hold(uuid, int, text) to anon, authenticated, service_role;
grant execute on function create_booking(text, uuid, text, text, text, booking_source, jsonb)
  to anon, authenticated, service_role;
grant execute on function release_hold(uuid) to authenticated, service_role;

-- ==================== 20260615120900_harden_pricing.sql ====================
-- Hardening pass (correctness/safety fixes):
--  1. create_booking now sources prices from the DB (activity_option_prices) and
--     forces items onto the occurrence's option — the client can no longer dictate
--     price or option ("prices only from the DB, never the client"). Also enforces
--     per-tier max_guests.
--  2. append_payment_event only confirms a booking when paid_minor >= amount_minor
--     (a partial payment must NOT confirm). Underpayment stays 'pending'.
--  3. create_hold rejects occurrences whose start time is already in the past.
-- These are additive `create or replace`s so they override the originals whether or
-- not the earlier migration was already applied.

create or replace function create_hold(
  p_occurrence_id uuid,
  p_quantity int,
  p_idempotency_key text
)
returns booking_holds
language plpgsql
security definer
set search_path = public
as $$
declare
  v_existing booking_holds;
  v_occ session_occurrences;
  v_available int;
  v_hold booking_holds;
begin
  if p_quantity is null or p_quantity <= 0 then
    raise exception 'invalid_quantity' using detail = 'quantity must be > 0';
  end if;

  select * into v_existing from booking_holds where idempotency_key = p_idempotency_key;
  if found then
    return v_existing;
  end if;

  select * into v_occ from session_occurrences where id = p_occurrence_id for update;
  if not found then
    raise exception 'occurrence_not_found';
  end if;
  if v_occ.status <> 'open' then
    raise exception 'occurrence_not_bookable' using detail = v_occ.status::text;
  end if;
  if v_occ.starts_at <= now() then
    raise exception 'occurrence_in_past';
  end if;

  v_available := v_occ.capacity - used_capacity(p_occurrence_id);
  if p_quantity > v_available then
    raise exception 'insufficient_capacity'
      using detail = format('requested %s, available %s', p_quantity, v_available);
  end if;

  insert into booking_holds (session_occurrence_id, quantity, idempotency_key)
  values (p_occurrence_id, p_quantity, p_idempotency_key)
  returning * into v_hold;
  return v_hold;
end;
$$;

create or replace function create_booking(
  p_idempotency_key text,
  p_hold_id uuid,
  p_customer_name text,
  p_customer_email text,
  p_customer_phone text,
  p_source booking_source,
  -- items: [{ "price_label": "Adult", "quantity": 2 }]; price + option come from the DB.
  p_items jsonb
)
returns bookings
language plpgsql
security definer
set search_path = public
as $$
declare
  v_existing bookings;
  v_hold booking_holds;
  v_occ session_occurrences;
  v_option_id uuid;
  v_booking bookings;
  v_item jsonb;
  v_label text;
  v_qty int;
  v_unit int;
  v_max int;
  v_total int := 0;
  v_qty_total int := 0;
begin
  select * into v_existing from bookings where idempotency_key = p_idempotency_key;
  if found then
    return v_existing;
  end if;

  select * into v_hold from booking_holds where id = p_hold_id for update;
  if not found then
    raise exception 'hold_not_found';
  end if;
  if v_hold.status <> 'active' or v_hold.expires_at <= now() then
    raise exception 'hold_not_active';
  end if;

  select * into v_occ from session_occurrences where id = v_hold.session_occurrence_id;
  v_option_id := v_occ.activity_option_id;

  -- Validate + price each line from the DB (never from the client payload).
  for v_item in select * from jsonb_array_elements(p_items) loop
    v_label := v_item ->> 'price_label';
    v_qty := (v_item ->> 'quantity')::int;
    if v_label is null or v_qty is null or v_qty <= 0 then
      raise exception 'invalid_item';
    end if;

    select amount_minor, max_guests into v_unit, v_max
    from activity_option_prices
    where activity_option_id = v_option_id and label = v_label;
    if not found then
      raise exception 'unknown_price_tier' using detail = v_label;
    end if;
    if v_max is not null and v_qty > v_max then
      raise exception 'exceeds_max_guests' using detail = format('%s: %s > %s', v_label, v_qty, v_max);
    end if;

    v_qty_total := v_qty_total + v_qty;
    v_total := v_total + (v_unit * v_qty);
  end loop;

  if v_qty_total <> v_hold.quantity then
    raise exception 'items_quantity_mismatch'
      using detail = format('items %s, hold %s', v_qty_total, v_hold.quantity);
  end if;

  insert into bookings (
    idempotency_key, customer_name, customer_email, customer_phone, source,
    status, total_minor, operator_payout_minor, agency_commission_minor
  )
  values (
    p_idempotency_key, p_customer_name, p_customer_email, p_customer_phone,
    coalesce(p_source, 'web'), 'payment_pending', v_total, v_total, 0
  )
  returning * into v_booking;

  for v_item in select * from jsonb_array_elements(p_items) loop
    v_label := v_item ->> 'price_label';
    v_qty := (v_item ->> 'quantity')::int;
    select amount_minor into v_unit
    from activity_option_prices
    where activity_option_id = v_option_id and label = v_label;

    insert into booking_items (
      booking_id, session_occurrence_id, activity_option_id, price_label,
      quantity, unit_amount_minor, subtotal_minor
    )
    values (v_booking.id, v_hold.session_occurrence_id, v_option_id, v_label, v_qty, v_unit, v_unit * v_qty);
  end loop;

  update booking_holds set booking_id = v_booking.id where id = v_hold.id;
  return v_booking;
end;
$$;

create or replace function append_payment_event(
  p_payment_id uuid,
  p_type text,
  p_provider_event_id text,
  p_amount_minor int,
  p_occurred_at timestamptz,
  p_payload jsonb
)
returns payments
language plpgsql
security definer
set search_path = public
as $$
declare
  v_payment payments;
  v_paid int;
  v_refunded int;
  v_failed boolean;
  v_state payment_state;
begin
  select * into v_payment from payments where id = p_payment_id for update;
  if not found then
    raise exception 'payment_not_found';
  end if;

  insert into payment_events (payment_id, type, provider_event_id, amount_minor, occurred_at, payload)
  values (
    p_payment_id, p_type, p_provider_event_id, coalesce(p_amount_minor, 0),
    coalesce(p_occurred_at, now()), coalesce(p_payload, '{}'::jsonb)
  )
  on conflict (payment_id, provider_event_id) do nothing;

  select
    coalesce(sum(amount_minor) filter (where type in ('paid', 'captured')), 0),
    coalesce(sum(amount_minor) filter (where type = 'refunded'), 0),
    bool_or(type = 'failed')
  into v_paid, v_refunded, v_failed
  from payment_events
  where payment_id = p_payment_id;

  if v_paid > 0 and v_refunded >= v_paid then
    v_state := 'refunded';
  elsif v_refunded > 0 then
    v_state := 'partially_refunded';
  elsif v_paid >= v_payment.amount_minor then
    v_state := 'paid';
  elsif v_paid > 0 then
    -- Money received but not the full amount yet: do NOT confirm.
    v_state := 'pending';
  elsif coalesce(v_failed, false) then
    v_state := 'failed';
  else
    v_state := 'pending';
  end if;

  update payments
  set status = v_state, paid_minor = v_paid, refunded_minor = v_refunded, updated_at = now()
  where id = p_payment_id
  returning * into v_payment;

  update bookings set payment_state = v_state, updated_at = now() where id = v_payment.booking_id;

  if v_state = 'paid' then
    update bookings set status = 'confirmed', updated_at = now()
    where id = v_payment.booking_id and status in ('draft', 'held', 'payment_pending');
    update booking_holds set status = 'consumed'
    where booking_id = v_payment.booking_id and status = 'active';
  elsif v_state = 'refunded' then
    update bookings set status = 'refunded', updated_at = now()
    where id = v_payment.booking_id and status <> 'cancelled';
  end if;

  return v_payment;
end;
$$;

-- ==================== 20260615121000_security_integrity_fixes.sql ====================
-- Security & integrity fixes from the Phase 1 adversarial review.
-- Additive: ALTERs + create-or-replace functions + a trigger + RLS tightening.

-- ---------------------------------------------------------------------------
-- Money columns -> bigint (int capped at ~21.4M EUR-cents; full-boat charters overflow)
-- ---------------------------------------------------------------------------
alter table activity_option_prices alter column amount_minor type bigint;
alter table bookings
  alter column total_minor type bigint,
  alter column agency_commission_minor type bigint,
  alter column operator_payout_minor type bigint;
alter table booking_items
  alter column unit_amount_minor type bigint,
  alter column subtotal_minor type bigint;
alter table payments
  alter column amount_minor type bigint,
  alter column paid_minor type bigint,
  alter column refunded_minor type bigint;
alter table payment_events alter column amount_minor type bigint;

-- ---------------------------------------------------------------------------
-- Integrity constraints
-- ---------------------------------------------------------------------------
-- Deleting a booking must not orphan an 'active' hold that keeps reserving a seat.
alter table booking_holds drop constraint if exists booking_holds_booking_id_fkey;
alter table booking_holds
  add constraint booking_holds_booking_id_fkey
  foreign key (booking_id) references bookings (id) on delete cascade;

-- Makes the seed occurrence generator idempotent and prevents duplicate departures.
alter table session_occurrences
  add constraint session_occurrences_option_start_key unique (activity_option_id, starts_at);

-- ---------------------------------------------------------------------------
-- RLS: bookings/payments are created ONLY via the SECURITY DEFINER RPCs.
-- Dropping the customer insert policy means RLS denies any direct customer insert
-- (no matching policy); the create_booking RPC bypasses RLS as the table owner.
-- ---------------------------------------------------------------------------
drop policy if exists bookings_insert on bookings;

-- Prevent privilege escalation: a customer must not be able to set/raise their own
-- role. Column-level GRANTs are ineffective here because a table-level GRANT already
-- covers every column, so we enforce with a trigger. service_role / the migration
-- owner (current_user not in the public roles) and existing staff may set roles.
create or replace function enforce_profile_role()
returns trigger
language plpgsql
security invoker
set search_path = public
as $$
begin
  if current_user not in ('anon', 'authenticated') then
    return new; -- service_role / owner / superuser
  end if;
  if is_staff() then
    return new; -- staff & admin may assign roles
  end if;
  if tg_op = 'INSERT' then
    new.role := 'customer';
  else
    new.role := old.role; -- self-update cannot change role
  end if;
  return new;
end;
$$;

drop trigger if exists profiles_role_guard on profiles;
create trigger profiles_role_guard
  before insert or update on profiles
  for each row execute function enforce_profile_role();

-- ---------------------------------------------------------------------------
-- create_booking: lock + validate the occurrence is still bookable, aggregate
-- quantities PER price tier (so per-tier max_guests is enforced on the summed
-- quantity, not per duplicated line), price from the DB. bigint money.
-- ---------------------------------------------------------------------------
create or replace function create_booking(
  p_idempotency_key text,
  p_hold_id uuid,
  p_customer_name text,
  p_customer_email text,
  p_customer_phone text,
  p_source booking_source,
  p_items jsonb
)
returns bookings
language plpgsql
security definer
set search_path = public
as $$
declare
  v_existing bookings;
  v_hold booking_holds;
  v_occ session_occurrences;
  v_option_id uuid;
  v_booking bookings;
  v_item jsonb;
  v_label text;
  v_qty int;
  v_unit bigint;
  v_max int;
  v_total bigint := 0;
  v_qty_total int := 0;
  v_agg jsonb := '{}'::jsonb;
begin
  select * into v_existing from bookings where idempotency_key = p_idempotency_key;
  if found then
    return v_existing;
  end if;

  select * into v_hold from booking_holds where id = p_hold_id for update;
  if not found then
    raise exception 'hold_not_found';
  end if;
  if v_hold.status <> 'active' or v_hold.expires_at <= now() then
    raise exception 'hold_not_active';
  end if;

  select * into v_occ from session_occurrences where id = v_hold.session_occurrence_id for update;
  if v_occ.status <> 'open' then
    raise exception 'occurrence_not_bookable' using detail = v_occ.status::text;
  end if;
  v_option_id := v_occ.activity_option_id;

  -- Aggregate quantity per price_label (collapses duplicate lines).
  for v_item in select * from jsonb_array_elements(p_items) loop
    v_label := v_item ->> 'price_label';
    v_qty := (v_item ->> 'quantity')::int;
    if v_label is null or v_qty is null or v_qty <= 0 then
      raise exception 'invalid_item';
    end if;
    v_agg := jsonb_set(v_agg, array[v_label], to_jsonb(coalesce((v_agg ->> v_label)::int, 0) + v_qty));
  end loop;

  -- Price + validate each aggregated tier from the DB.
  for v_label, v_qty in select key, (value::text)::int from jsonb_each(v_agg) loop
    select amount_minor, max_guests into v_unit, v_max
    from activity_option_prices
    where activity_option_id = v_option_id and label = v_label;
    if not found then
      raise exception 'unknown_price_tier' using detail = v_label;
    end if;
    if v_max is not null and v_qty > v_max then
      raise exception 'exceeds_max_guests' using detail = format('%s: %s > %s', v_label, v_qty, v_max);
    end if;
    v_qty_total := v_qty_total + v_qty;
    v_total := v_total + (v_unit * v_qty);
  end loop;

  if v_qty_total <> v_hold.quantity then
    raise exception 'items_quantity_mismatch'
      using detail = format('items %s, hold %s', v_qty_total, v_hold.quantity);
  end if;

  insert into bookings (
    idempotency_key, customer_name, customer_email, customer_phone, source,
    status, total_minor, operator_payout_minor, agency_commission_minor
  )
  values (
    p_idempotency_key, p_customer_name, p_customer_email, p_customer_phone,
    coalesce(p_source, 'web'), 'payment_pending', v_total, v_total, 0
  )
  returning * into v_booking;

  for v_label, v_qty in select key, (value::text)::int from jsonb_each(v_agg) loop
    select amount_minor into v_unit
    from activity_option_prices
    where activity_option_id = v_option_id and label = v_label;
    insert into booking_items (
      booking_id, session_occurrence_id, activity_option_id, price_label,
      quantity, unit_amount_minor, subtotal_minor
    )
    values (v_booking.id, v_hold.session_occurrence_id, v_option_id, v_label, v_qty, v_unit, v_unit * v_qty);
  end loop;

  update booking_holds set booking_id = v_booking.id where id = v_hold.id;
  return v_booking;
end;
$$;

-- ---------------------------------------------------------------------------
-- append_payment_event: on first full payment, RE-CHECK capacity under an
-- occurrence lock before confirming. If the seat is gone (hold expired + resold),
-- route to refund_pending instead of overselling. A payment landing on a dead
-- (expired/cancelled) booking also routes to refund_pending. Refund releases holds.
-- ---------------------------------------------------------------------------
-- Drop the previous int-signature version (we widen p_amount_minor to bigint).
drop function if exists append_payment_event(uuid, text, text, integer, timestamptz, jsonb);

create or replace function append_payment_event(
  p_payment_id uuid,
  p_type text,
  p_provider_event_id text,
  p_amount_minor bigint,
  p_occurred_at timestamptz,
  p_payload jsonb
)
returns payments
language plpgsql
security definer
set search_path = public
as $$
declare
  v_payment payments;
  v_paid bigint;
  v_refunded bigint;
  v_failed boolean;
  v_state payment_state;
  v_booking_status booking_status;
  v_occ_id uuid;
  v_needed bigint;
  v_cap bigint;
  v_used_conf bigint;
  v_used_hold bigint;
  v_oversold boolean := false;
begin
  select * into v_payment from payments where id = p_payment_id for update;
  if not found then
    raise exception 'payment_not_found';
  end if;

  insert into payment_events (payment_id, type, provider_event_id, amount_minor, occurred_at, payload)
  values (
    p_payment_id, p_type, p_provider_event_id, coalesce(p_amount_minor, 0),
    coalesce(p_occurred_at, now()), coalesce(p_payload, '{}'::jsonb)
  )
  on conflict (payment_id, provider_event_id) do nothing;

  select
    coalesce(sum(amount_minor) filter (where type in ('paid', 'captured')), 0),
    coalesce(sum(amount_minor) filter (where type = 'refunded'), 0),
    bool_or(type = 'failed')
  into v_paid, v_refunded, v_failed
  from payment_events
  where payment_id = p_payment_id;

  if v_paid > 0 and v_refunded >= v_paid then
    v_state := 'refunded';
  elsif v_paid > 0 and v_refunded > 0 then
    v_state := 'partially_refunded';
  elsif v_paid >= v_payment.amount_minor then
    v_state := 'paid';
  elsif v_paid > 0 then
    v_state := 'pending'; -- underpaid: do not confirm
  elsif coalesce(v_failed, false) then
    v_state := 'failed';
  else
    v_state := 'pending';
  end if;

  update payments
  set status = v_state, paid_minor = v_paid, refunded_minor = v_refunded, updated_at = now()
  where id = p_payment_id
  returning * into v_payment;

  update bookings set payment_state = v_state, updated_at = now() where id = v_payment.booking_id;

  if v_state = 'paid' then
    select status into v_booking_status from bookings where id = v_payment.booking_id;

    if v_booking_status in ('draft', 'held', 'payment_pending') then
      -- Re-validate capacity per occurrence, excluding this booking's own items/holds.
      for v_occ_id in
        select distinct session_occurrence_id from booking_items where booking_id = v_payment.booking_id
      loop
        perform 1 from session_occurrences where id = v_occ_id for update;
        select coalesce(sum(quantity), 0) into v_needed
        from booking_items where booking_id = v_payment.booking_id and session_occurrence_id = v_occ_id;
        select capacity into v_cap from session_occurrences where id = v_occ_id;
        select coalesce(sum(bi.quantity), 0) into v_used_conf
        from booking_items bi join bookings b on b.id = bi.booking_id
        where bi.session_occurrence_id = v_occ_id
          and b.status in ('confirmed', 'completed')
          and b.id <> v_payment.booking_id;
        select coalesce(sum(h.quantity), 0) into v_used_hold
        from booking_holds h
        where h.session_occurrence_id = v_occ_id
          and h.status = 'active' and h.expires_at > now()
          and (h.booking_id is null or h.booking_id <> v_payment.booking_id);
        if v_needed > v_cap - v_used_conf - v_used_hold then
          v_oversold := true;
        end if;
      end loop;

      if v_oversold then
        update bookings set status = 'refund_pending', updated_at = now() where id = v_payment.booking_id;
      else
        update bookings set status = 'confirmed', updated_at = now() where id = v_payment.booking_id;
        update booking_holds set status = 'consumed'
        where booking_id = v_payment.booking_id and status = 'active';
      end if;
    elsif v_booking_status not in ('confirmed', 'completed') then
      -- Money captured on an expired/cancelled booking: must be refunded, not confirmed.
      update bookings set status = 'refund_pending', updated_at = now() where id = v_payment.booking_id;
    end if;
  elsif v_state = 'refunded' then
    update bookings set status = 'refunded', updated_at = now()
    where id = v_payment.booking_id and status <> 'cancelled';
    update booking_holds set status = 'released'
    where booking_id = v_payment.booking_id and status = 'active';
  end if;

  return v_payment;
end;
$$;

revoke execute on function append_payment_event(uuid, text, text, bigint, timestamptz, jsonb) from public;
grant execute on function append_payment_event(uuid, text, text, bigint, timestamptz, jsonb) to service_role;

-- ==================== 20260615121200_api_functions.sql ====================
-- Service-facing API functions. The TypeScript service layer ONLY calls these
-- (via db.rpc), so it is verified against real Postgres with no mock divergence.
-- Reads are SECURITY INVOKER (RLS applies: public sees published only); writes are
-- SECURITY DEFINER and reuse the hardened Phase 1 booking RPCs. All return jsonb.

-- Shared booking DTO builder (camelCase, EUR). SECURITY INVOKER so it inherits the
-- caller's RLS when used in api_get_booking, but returns the just-created booking
-- when called from the SECURITY DEFINER api_book (definer context = owner).
create or replace function booking_json(p_booking_id uuid)
returns jsonb
language sql
stable
security invoker
set search_path = public
as $$
  select jsonb_build_object(
    'id', b.id, 'ref', b.ref, 'status', b.status, 'paymentState', b.payment_state,
    'customerName', b.customer_name, 'customerEmail', b.customer_email,
    'totalEur', b.total_minor::float / 100, 'currency', b.currency, 'source', b.source,
    'createdAt', b.created_at,
    'items', coalesce((
      select jsonb_agg(jsonb_build_object(
        'priceLabel', bi.price_label, 'quantity', bi.quantity,
        'unitAmountEur', bi.unit_amount_minor::float / 100, 'subtotalEur', bi.subtotal_minor::float / 100,
        'occurrenceId', bi.session_occurrence_id
      ))
      from booking_items bi where bi.booking_id = b.id
    ), '[]'::jsonb)
  )
  from bookings b where b.id = p_booking_id;
$$;

-- ---------------------------------------------------------------------------
-- Catalogue search (paginated). p = { q?, category?, type?, page?, pageSize? }
-- ---------------------------------------------------------------------------
create or replace function api_search_activities(p jsonb)
returns jsonb
language sql
stable
security invoker
set search_path = public
as $$
  with filtered as (
    select a.*
    from activities a
    where a.status = 'published'
      and (p ->> 'category' is null or a.category::text = p ->> 'category')
      and (p ->> 'type' is null or a.type::text = p ->> 'type')
      and (
        p ->> 'q' is null
        or a.title ilike '%' || (p ->> 'q') || '%'
        or coalesce(a.summary, '') ilike '%' || (p ->> 'q') || '%'
      )
  ),
  paged as (
    select * from filtered
    order by rating_count desc, title
    limit coalesce((p ->> 'pageSize')::int, 20)
    offset (coalesce((p ->> 'page')::int, 1) - 1) * coalesce((p ->> 'pageSize')::int, 20)
  )
  select jsonb_build_object(
    'items', coalesce((
      select jsonb_agg(jsonb_build_object(
        'id', x.id, 'slug', x.slug, 'type', x.type, 'title', x.title, 'summary', x.summary,
        'category', x.category, 'location', x.location, 'durationMinutes', x.duration_minutes,
        'ratingAvg', x.rating_avg, 'ratingCount', x.rating_count,
        'fromPriceEur', (
          select min(pr.amount_minor)::float / 100
          from activity_option_prices pr
          join activity_options o on o.id = pr.activity_option_id
          where o.activity_id = x.id
        ),
        'heroImage', (
          select jsonb_build_object('id', img.id, 'url', img.url, 'alt', img.alt, 'position', img.position)
          from activity_images img where img.activity_id = x.id order by img.position limit 1
        )
      ))
      from paged x
    ), '[]'::jsonb),
    'total', (select count(*)::int from filtered),
    'page', coalesce((p ->> 'page')::int, 1),
    'pageSize', coalesce((p ->> 'pageSize')::int, 20)
  );
$$;

-- ---------------------------------------------------------------------------
